if (!function_exists('fin_t')) {
  function fin_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('fin_h')) {
  function fin_h($key, $fallback = '') { return htmlspecialchars((string) fin_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('fin_js')) {
  function fin_js($key, $fallback = '') { return json_encode(fin_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
$initialOutputBufferLevel=ob_get_level();ob_start();session_start();include __DIR__."/../../inc/config.php";require_once __DIR__."/../../inc/lib/PHPExcel.php";require_once __DIR__."/../../inc/excel_style_helper.php";session_check_json();
function ti_a_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function ti_a_n($v){return number_format((float)$v,2,'.',',');}
function ti_a_amt($v){return round((float)str_replace(',','',trim((string)$v)),2);}
function ti_a_date($d){$x=DateTime::createFromFormat('Y-m-d',$d);return $x&&$x->format('Y-m-d')===$d;}
function ti_a_user(){return $_SESSION['username']??'system';}
function ti_a_json($s,$m='',$e=array()){header('Content-Type: application/json');echo json_encode(array_merge(array('status'=>$s,'message'=>$m),$e));exit;}
function ti_a_list($db,$dir,$period,$status,$valid){$w="ti.tax_direction=? AND ti.tax_period=?";$p=array($dir,$period);if($status!==''){$w.=" AND ti.status=?";$p[]=$status;}if($valid!==''){$w.=" AND ti.validation_status=?";$p[]=$valid;}return $db->query("SELECT ti.*,tc.tax_code FROM erp_tax_invoice ti LEFT JOIN erp_tax_code tc ON tc.id=ti.tax_code_id WHERE $w ORDER BY ti.tax_invoice_date DESC,ti.id DESC",$p);}
