  ti_a_json('success','Draft tax invoice berhasil disimpan.');
 }
 if($act==='filter'){ $dir=$_POST['tax_direction']==='IN'?'IN':'OUT';$period=$_POST['tax_period']??date('Y-m');$status=trim($_POST['status']??'');$valid=trim($_POST['validation_status']??'');$rows=ti_a_list($db,$dir,$period,$status,$valid);$html='';$dpp=0;$vat=0;$n=0;foreach($rows as $r){$n++;$dpp+=(float)$r->dpp_amount;$vat+=(float)$r->vat_amount;$cls=$r->status==='POSTED'?'success':($r->status==='CANCELLED'?'danger':'warning');$partner=trim($r->partner_code.' - '.$r->partner_name,' -');$source=trim($r->source_module.' '.$r->source_document_no);$actn='<div class="btn-group btn-group-xs"><button class="btn btn-info ti-detail" data-no="'.ti_a_h($r->tax_invoice_no).'" data-date="'.ti_a_h($r->tax_invoice_date).'" data-partner="'.ti_a_h($partner).'" data-source="'.ti_a_h($source).'" data-dpp="'.ti_a_h(ti_a_n($r->dpp_amount)).'" data-vat="'.ti_a_h(ti_a_n($r->vat_amount)).'" data-status="'.ti_a_h($r->status).'" data-validation="'.ti_a_h($r->validation_status).'" title="'.fin_h('common_detail', 'Detail').'"><i class="fa fa-eye"></i></button>';if($r->status==='DRAFT')$actn.='<button class="btn btn-success ti-post" data-id="'.$r->id.'"><i class="fa fa-check"></i></button>';$actn.='<button class="btn btn-danger ti-cancel" data-id="'.$r->id.'"><i class="fa fa-ban"></i></button></div>';$html.='<tr><td>'.$n.'</td><td>'.ti_a_h($r->tax_invoice_no).'</td><td>'.ti_a_h($r->tax_invoice_date).'</td><td>'.ti_a_h($partner).'</td><td>'.ti_a_h($source).'</td><td class="text-right">'.ti_a_n($r->dpp_amount).'</td><td class="text-right">'.ti_a_n($r->vat_amount).'</td><td><span class="label label-'.$cls.'">'.ti_a_h($r->status).'</span></td><td>'.ti_a_h($r->validation_status).'</td><td>'.$actn.'</td></tr>';}if($n===0)$html='<tr><td colspan="10" class="text-center text-muted">Tidak ada data.</td></tr>';ti_a_json('success','OK',array('html'=>$html,'dpp'=>ti_a_n($dpp),'vat'=>ti_a_n($vat),'count'=>$n));}
